ALTER TABLE regulations ADD COLUMN jurisdiction_type RegulatoryJurisdictionType DEFAULT null;
ALTER TABLE regulations ADD COLUMN acronym character varying (24) DEFAULT null;
ALTER TABLE regulations ADD COLUMN description text DEFAULT null;
ALTER TABLE regulations ADD COLUMN body text DEFAULT null;
ALTER TABLE regulations ADD COLUMN regulated_party text DEFAULT null;
ALTER TABLE regulations ADD COLUMN protected_party text DEFAULT null;
ALTER TABLE regulations ADD COLUMN protected_information text DEFAULT null;

rollback.sql:
